function DefaultCurrency49() {}
DefaultCurrency49.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency49.tabIndex = -1;
DefaultCurrency49.maxLength = 1;
DefaultCurrency49.isReadOnly = function(){return true;}
DefaultCurrency49.isTemporary = function(){return true;}
DefaultCurrency49.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
